window.BIBLE["1Peter"] = {"1":{"chapter":"1","title":"BORN AGAIN TO A LIVING HOPE","verses":{"1":{"text":"Peter, an apostle of Jesus Christ, to the strangers scattered throughout Pontus, Galatia, Cappadocia, Asia, and Bithynia,","ref":"1 Peter 1:1","synthesized":"Peter, an apostle of Jesus Christ,  To the elect who are exiles of the Dispersion throughout Pontus, Galatia, Cappadocia, Asia, and Bithynia, chosen","sources":{"KJV":{"text":"Peter, an apostle of Jesus Christ, to the strangers scattered throughout Pontus, Galatia, Cappadocia, Asia, and Bithynia,"},"BSB":{"text":"Peter, an apostle of Jesus Christ,  To the elect who are exiles of the Dispersion throughout Pontus, Galatia, Cappadocia, Asia, and Bithynia, chosen"}},"definableWords":["apostle","Christ"],"peopleInVerse":["Peter","Jesus"]},"2":{"text":"Elect according to the foreknowledge of God the Father, through sanctification of the Spirit, unto obedience and sprinkling of the blood of Jesus Christ: Grace unto you, and peace, be multiplied.","ref":"1 Peter 1:2","synthesized":"according to the foreknowledge of God the Father and sanctified by the Spirit for obedience to Jesus Christ and sprinkling by His blood:  Grace and peace be yours in abundance.","sources":{"KJV":{"text":"Elect according to the foreknowledge of God the Father, through sanctification of the Spirit, unto obedience and sprinkling of the blood of Jesus Christ: Grace unto you, and peace, be multiplied."},"BSB":{"text":"according to the foreknowledge of God the Father and sanctified by the Spirit for obedience to Jesus Christ and sprinkling by His blood:  Grace and peace be yours in abundance."}},"definableWords":["God","Father","Spirit","Christ","blood","grace","peace"],"peopleInVerse":["Jesus"]},"3":{"text":"Blessed be the God and Father of our Lord Jesus Christ, which according to his abundant mercy hath begotten us again unto a lively hope by the resurrection of Jesus Christ from the dead,","ref":"1 Peter 1:3","synthesized":"Blessed be the God and Father of our Lord Jesus Christ! By His great mercy He has given us new birth into a living hope through the resurrection of Jesus Christ from the dead,","sources":{"KJV":{"text":"Blessed be the God and Father of our Lord Jesus Christ, which according to his abundant mercy hath begotten us again unto a lively hope by the resurrection of Jesus Christ from the dead,"},"BSB":{"text":"Blessed be the God and Father of our Lord Jesus Christ! By His great mercy He has given us new birth into a living hope through the resurrection of Jesus Christ from the dead,"}},"definableWords":["blessed","God","Father","Lord","Christ","great","mercy","living","hope","resurrection"],"peopleInVerse":["Jesus"]},"4":{"text":"To an inheritance incorruptible, and undefiled, and that fadeth not away, reserved in heaven for you,","ref":"1 Peter 1:4","synthesized":"and into an inheritance that is imperishable, undefiled, and unfading, reserved in heaven for you,","sources":{"KJV":{"text":"To an inheritance incorruptible, and undefiled, and that fadeth not away, reserved in heaven for you,"},"BSB":{"text":"and into an inheritance that is imperishable, undefiled, and unfading, reserved in heaven for you,"}},"definableWords":["heaven"],"peopleInVerse":[]},"5":{"text":"Who are kept by the power of God through faith unto salvation ready to be revealed in the last time.","ref":"1 Peter 1:5","synthesized":"who through faith are shielded by God’s power for the salvation that is ready to be revealed in the last time.","sources":{"KJV":{"text":"Who are kept by the power of God through faith unto salvation ready to be revealed in the last time."},"BSB":{"text":"who through faith are shielded by God’s power for the salvation that is ready to be revealed in the last time."}},"definableWords":["faith","God","salvation"],"peopleInVerse":[]},"6":{"text":"Wherein ye greatly rejoice, though now for a season, if need be, ye are in heaviness through manifold temptations:","ref":"1 Peter 1:6","synthesized":"In this you greatly rejoice, though now for a little while you may have had to suffer grief in various trials","sources":{"KJV":{"text":"Wherein ye greatly rejoice, though now for a season, if need be, ye are in heaviness through manifold temptations:"},"BSB":{"text":"In this you greatly rejoice, though now for a little while you may have had to suffer grief in various trials"}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"That the trial of your faith, being much more precious than of gold that perisheth, though it be tried with fire, might be found unto praise and honour and glory at the appearing of Jesus Christ:","ref":"1 Peter 1:7","synthesized":"so that the proven character of your faith—more precious than gold, which perishes even though refined by fire—may result in praise, glory, and honor at the revelation of Jesus Christ.","sources":{"KJV":{"text":"That the trial of your faith, being much more precious than of gold that perisheth, though it be tried with fire, might be found unto praise and honour and glory at the appearing of Jesus Christ:"},"BSB":{"text":"so that the proven character of your faith—more precious than gold, which perishes even though refined by fire—may result in praise, glory, and honor at the revelation of Jesus Christ."}},"definableWords":["faith","praise","glory","Christ"],"peopleInVerse":["Jesus"]},"8":{"text":"Whom having not seen, ye love; in whom, though now ye see him not, yet believing, ye rejoice with joy unspeakable and full of glory:","ref":"1 Peter 1:8","synthesized":"Though you have not seen Him, you love Him; and though you do not see Him now, you believe in Him and rejoice with an inexpressible and glorious joy,","sources":{"KJV":{"text":"Whom having not seen, ye love; in whom, though now ye see him not, yet believing, ye rejoice with joy unspeakable and full of glory:"},"BSB":{"text":"Though you have not seen Him, you love Him; and though you do not see Him now, you believe in Him and rejoice with an inexpressible and glorious joy,"}},"definableWords":["love","see","joy"],"peopleInVerse":[]},"9":{"text":"Receiving the end of your faith, even the salvation of your souls.","ref":"1 Peter 1:9","synthesized":"now that you are receiving the goal of your faith, the salvation of your souls.","sources":{"KJV":{"text":"Receiving the end of your faith, even the salvation of your souls."},"BSB":{"text":"now that you are receiving the goal of your faith, the salvation of your souls."}},"definableWords":["faith","salvation"],"peopleInVerse":[]},"10":{"text":"Of which salvation the prophets have enquired and searched diligently, who prophesied of the grace that should come unto you:","ref":"1 Peter 1:10","synthesized":"Concerning this salvation, the prophets who foretold the grace to come to you searched and investigated carefully,","sources":{"KJV":{"text":"Of which salvation the prophets have enquired and searched diligently, who prophesied of the grace that should come unto you:"},"BSB":{"text":"Concerning this salvation, the prophets who foretold the grace to come to you searched and investigated carefully,"}},"definableWords":["salvation","grace"],"peopleInVerse":[]},"11":{"text":"Searching what, or what manner of time the Spirit of Christ which was in them did signify, when it testified beforehand the sufferings of Christ, and the glory that should follow.","ref":"1 Peter 1:11","synthesized":"trying to determine the time and setting to which the Spirit of Christ in them was pointing when He predicted the sufferings of Christ and the glories to follow.","sources":{"KJV":{"text":"Searching what, or what manner of time the Spirit of Christ which was in them did signify, when it testified beforehand the sufferings of Christ, and the glory that should follow."},"BSB":{"text":"trying to determine the time and setting to which the Spirit of Christ in them was pointing when He predicted the sufferings of Christ and the glories to follow."}},"definableWords":["Spirit","Christ"],"peopleInVerse":[]},"12":{"text":"Unto whom it was revealed, that not unto themselves, but unto us they did minister the things, which are now reported unto you by them that have preached the gospel unto you with the Holy Ghost sent down from heaven; which things the angels desire to look into.","ref":"1 Peter 1:12","synthesized":"It was revealed to them that they were not serving themselves, but you, when they foretold the things now announced by those who preached the gospel to you by the Holy Spirit sent from heaven. Even angels long to look into these things.","sources":{"KJV":{"text":"Unto whom it was revealed, that not unto themselves, but unto us they did minister the things, which are now reported unto you by them that have preached the gospel unto you with the Holy Ghost sent down from heaven; which things the angels desire to look into."},"BSB":{"text":"It was revealed to them that they were not serving themselves, but you, when they foretold the things now announced by those who preached the gospel to you by the Holy Spirit sent from heaven. Even angels long to look into these things."}},"definableWords":["gospel","holy","Spirit","heaven"],"peopleInVerse":[]},"13":{"text":"Wherefore gird up the loins of your mind, be sober, and hope to the end for the grace that is to be brought unto you at the revelation of Jesus Christ;","ref":"1 Peter 1:13","synthesized":"Therefore prepare your minds for action. Be sober-minded. Set your hope fully on the grace to be given you at the revelation of Jesus Christ.","sources":{"KJV":{"text":"Wherefore gird up the loins of your mind, be sober, and hope to the end for the grace that is to be brought unto you at the revelation of Jesus Christ;"},"BSB":{"text":"Therefore prepare your minds for action. Be sober-minded. Set your hope fully on the grace to be given you at the revelation of Jesus Christ."}},"definableWords":["hope","grace","Christ"],"peopleInVerse":["Jesus"]},"14":{"text":"As obedient children, not fashioning yourselves according to the former lusts in your ignorance:","ref":"1 Peter 1:14","synthesized":"As obedient children, do not conform to the passions of your former ignorance.","sources":{"KJV":{"text":"As obedient children, not fashioning yourselves according to the former lusts in your ignorance:"},"BSB":{"text":"As obedient children, do not conform to the passions of your former ignorance."}},"definableWords":[],"peopleInVerse":[]},"15":{"text":"But as he which hath called you is holy, so be ye holy in all manner of conversation;","ref":"1 Peter 1:15","synthesized":"But just as He who called you is holy, so be holy in all you do,","sources":{"KJV":{"text":"But as he which hath called you is holy, so be ye holy in all manner of conversation;"},"BSB":{"text":"But just as He who called you is holy, so be holy in all you do,"}},"definableWords":["holy"],"peopleInVerse":[]},"16":{"text":"Because it is written, Be ye holy; for I am holy.","ref":"1 Peter 1:16","synthesized":"for it is written: “Be holy, because I am holy.”","sources":{"KJV":{"text":"Because it is written, Be ye holy; for I am holy."},"BSB":{"text":"for it is written: “Be holy, because I am holy.”"}},"definableWords":["holy"],"peopleInVerse":[]},"17":{"text":"And if ye call on the Father, who without respect of persons judgeth according to every man’s work, pass the time of your sojourning here in fear:","ref":"1 Peter 1:17","synthesized":"Since you call on a Father who judges each one’s work impartially, conduct yourselves in reverent fear during your stay as foreigners.","sources":{"KJV":{"text":"And if ye call on the Father, who without respect of persons judgeth according to every man’s work, pass the time of your sojourning here in fear:"},"BSB":{"text":"Since you call on a Father who judges each one’s work impartially, conduct yourselves in reverent fear during your stay as foreigners."}},"definableWords":["Father","one","work","fear"],"peopleInVerse":[]},"18":{"text":"Forasmuch as ye know that ye were not redeemed with corruptible things, as silver and gold, from your vain conversation received by tradition from your fathers;","ref":"1 Peter 1:18","synthesized":"For you know that it was not with perishable things such as silver or gold that you were redeemed from the empty way of life you inherited from your forefathers,","sources":{"KJV":{"text":"Forasmuch as ye know that ye were not redeemed with corruptible things, as silver and gold, from your vain conversation received by tradition from your fathers;"},"BSB":{"text":"For you know that it was not with perishable things such as silver or gold that you were redeemed from the empty way of life you inherited from your forefathers,"}},"definableWords":["or","way","life"],"peopleInVerse":[]},"19":{"text":"But with the precious blood of Christ, as of a lamb without blemish and without spot:","ref":"1 Peter 1:19","synthesized":"but with the precious blood of Christ, a lamb without blemish or spot.","sources":{"KJV":{"text":"But with the precious blood of Christ, as of a lamb without blemish and without spot:"},"BSB":{"text":"but with the precious blood of Christ, a lamb without blemish or spot."}},"definableWords":["blood","Christ","Lamb","or"],"peopleInVerse":[]},"20":{"text":"Who verily was foreordained before the foundation of the world, but was manifest in these last times for you,","ref":"1 Peter 1:20","synthesized":"He was known before the foundation of the world, but was revealed in the last times for your sake.","sources":{"KJV":{"text":"Who verily was foreordained before the foundation of the world, but was manifest in these last times for you,"},"BSB":{"text":"He was known before the foundation of the world, but was revealed in the last times for your sake."}},"definableWords":[],"peopleInVerse":[]},"21":{"text":"Who by him do believe in God, that raised him up from the dead, and gave him glory; that your faith and hope might be in God.","ref":"1 Peter 1:21","synthesized":"Through Him you believe in God, who raised Him from the dead and glorified Him; and so your faith and hope are in God.","sources":{"KJV":{"text":"Who by him do believe in God, that raised him up from the dead, and gave him glory; that your faith and hope might be in God."},"BSB":{"text":"Through Him you believe in God, who raised Him from the dead and glorified Him; and so your faith and hope are in God."}},"definableWords":["God","faith","hope"],"peopleInVerse":[]},"22":{"text":"Seeing ye have purified your souls in obeying the truth through the Spirit unto unfeigned love of the brethren, see that ye love one another with a pure heart fervently:","ref":"1 Peter 1:22","synthesized":"Since you have purified your souls by obedience to the truth so that you have a genuine love for your brothers, love one another deeply, from a pure heart.","sources":{"KJV":{"text":"Seeing ye have purified your souls in obeying the truth through the Spirit unto unfeigned love of the brethren, see that ye love one another with a pure heart fervently:"},"BSB":{"text":"Since you have purified your souls by obedience to the truth so that you have a genuine love for your brothers, love one another deeply, from a pure heart."}},"definableWords":["truth","love","one","heart"],"peopleInVerse":[]},"23":{"text":"Being born again, not of corruptible seed, but of incorruptible, by the word of God, which liveth and abideth for ever.","ref":"1 Peter 1:23","synthesized":"For you have been born again, not of perishable seed, but of imperishable, through the living and enduring word of God.","sources":{"KJV":{"text":"Being born again, not of corruptible seed, but of incorruptible, by the word of God, which liveth and abideth for ever."},"BSB":{"text":"For you have been born again, not of perishable seed, but of imperishable, through the living and enduring word of God."}},"definableWords":["seed","living","word","God"],"peopleInVerse":[]},"24":{"text":"For all flesh is as grass, and all the glory of man as the flower of grass. The grass withereth, and the flower thereof falleth away:","ref":"1 Peter 1:24","synthesized":"For,  “All flesh is like grass, and all its glory like the flowers of the field; the grass withers and the flowers fall,","sources":{"KJV":{"text":"For all flesh is as grass, and all the glory of man as the flower of grass. The grass withereth, and the flower thereof falleth away:"},"BSB":{"text":"For,  “All flesh is like grass, and all its glory like the flowers of the field; the grass withers and the flowers fall,"}},"definableWords":["flesh","glory","field"],"peopleInVerse":[]},"25":{"text":"But the word of the Lord endureth for ever. And this is the word which by the gospel is preached unto you.","ref":"1 Peter 1:25","synthesized":"but the word of the Lord stands forever.”   And this is the word that was proclaimed to you.","sources":{"KJV":{"text":"But the word of the Lord endureth for ever. And this is the word which by the gospel is preached unto you."},"BSB":{"text":"but the word of the Lord stands forever.”   And this is the word that was proclaimed to you."}},"definableWords":["word","Lord"],"peopleInVerse":[]}}},"2":{"chapter":"2","title":"A ROYAL PRIESTHOOD","verses":{"1":{"text":"Wherefore laying aside all malice, and all guile, and hypocrisies, and envies, and all evil speakings,","ref":"1 Peter 2:1","synthesized":"Rid yourselves, therefore, of all malice, deceit, hypocrisy, envy, and slander.","sources":{"KJV":{"text":"Wherefore laying aside all malice, and all guile, and hypocrisies, and envies, and all evil speakings,"},"BSB":{"text":"Rid yourselves, therefore, of all malice, deceit, hypocrisy, envy, and slander."}},"definableWords":[],"peopleInVerse":[],"kingdomLens":"Peter writes to Christians scattered through Roman provinces. He calls them: 'ye are a chosen generation, a royal priesthood, an holy nation, a peculiar people; that ye should shew forth the praises of him who hath called you out of darkness into his marvellous light' (2:9). The temple is being rebuilt — out of LIVING STONES. Christ is the chief cornerstone.","cultural":{"title":"A royal priesthood — a peculiar people","detail":"'Peculiar' in 1611 English meant 'special, set apart' — not 'weird.' The Greek (peripoiesis) means 'possession, treasure.' We are God's special treasure. Peter writes from Rome (called 'Babylon' in 5:13) under increasing Roman hostility — emphasizing identity for Christians scattered across the empire.","sources":"SWRV Kingdom Study Protocol — synthesis from approved library (Rule 06)"}},"2":{"text":"As newborn babes, desire the sincere milk of the word, that ye may grow thereby:","ref":"1 Peter 2:2","synthesized":"Like newborn babies, crave pure spiritual milk, so that by it you may grow up in your salvation,","sources":{"KJV":{"text":"As newborn babes, desire the sincere milk of the word, that ye may grow thereby:"},"BSB":{"text":"Like newborn babies, crave pure spiritual milk, so that by it you may grow up in your salvation,"}},"definableWords":["salvation"],"peopleInVerse":[]},"3":{"text":"If so be ye have tasted that the Lord is gracious.","ref":"1 Peter 2:3","synthesized":"now that you have tasted that the Lord is good.","sources":{"KJV":{"text":"If so be ye have tasted that the Lord is gracious."},"BSB":{"text":"now that you have tasted that the Lord is good."}},"definableWords":["Lord","good"],"peopleInVerse":[]},"4":{"text":"To whom coming, as unto a living stone, disallowed indeed of men, but chosen of God, and precious,","ref":"1 Peter 2:4","synthesized":"As you come to Him, the living stone, rejected by men but chosen and precious in God’s sight,","sources":{"KJV":{"text":"To whom coming, as unto a living stone, disallowed indeed of men, but chosen of God, and precious,"},"BSB":{"text":"As you come to Him, the living stone, rejected by men but chosen and precious in God’s sight,"}},"definableWords":["living","stone","men","God"],"peopleInVerse":[]},"5":{"text":"Ye also, as lively stones, are built up a spiritual house, an holy priesthood, to offer up spiritual sacrifices, acceptable to God by Jesus Christ.","ref":"1 Peter 2:5","synthesized":"you also, like living stones, are being built into a spiritual house to be a holy priesthood, offering spiritual sacrifices acceptable to God through Jesus Christ.","sources":{"KJV":{"text":"Ye also, as lively stones, are built up a spiritual house, an holy priesthood, to offer up spiritual sacrifices, acceptable to God by Jesus Christ."},"BSB":{"text":"you also, like living stones, are being built into a spiritual house to be a holy priesthood, offering spiritual sacrifices acceptable to God through Jesus Christ."}},"definableWords":["living","house","holy","offering","God","Christ"],"peopleInVerse":["Jesus"]},"6":{"text":"Wherefore also it is contained in the scripture, Behold, I lay in Sion a chief corner stone, elect, precious: and he that believeth on him shall not be confounded.","ref":"1 Peter 2:6","synthesized":"For it stands in Scripture:  “See, I lay in Zion a stone, a chosen and precious cornerstone; and the one who believes in Him will never be put to shame.”","sources":{"KJV":{"text":"Wherefore also it is contained in the scripture, Behold, I lay in Sion a chief corner stone, elect, precious: and he that believeth on him shall not be confounded."},"BSB":{"text":"For it stands in Scripture:  “See, I lay in Zion a stone, a chosen and precious cornerstone; and the one who believes in Him will never be put to shame.”"}},"definableWords":["see","Zion","stone","one"],"peopleInVerse":[]},"7":{"text":"Unto you therefore which believe he is precious: but unto them which be disobedient, the stone which the builders disallowed, the same is made the head of the corner,","ref":"1 Peter 2:7","synthesized":"To you who believe, then, this stone is precious. But to those who do not believe,  “The stone the builders rejected has become the cornerstone,”","sources":{"KJV":{"text":"Unto you therefore which believe he is precious: but unto them which be disobedient, the stone which the builders disallowed, the same is made the head of the corner,"},"BSB":{"text":"To you who believe, then, this stone is precious. But to those who do not believe,  “The stone the builders rejected has become the cornerstone,”"}},"definableWords":["stone"],"peopleInVerse":[]},"8":{"text":"And a stone of stumbling, and a rock of offence, even to them which stumble at the word, being disobedient: whereunto also they were appointed.","ref":"1 Peter 2:8","synthesized":"and,  “A stone of stumbling and a rock of offense.”   They stumble because they disobey the word—and to this they were appointed.","sources":{"KJV":{"text":"And a stone of stumbling, and a rock of offence, even to them which stumble at the word, being disobedient: whereunto also they were appointed."},"BSB":{"text":"and,  “A stone of stumbling and a rock of offense.”   They stumble because they disobey the word—and to this they were appointed."}},"definableWords":["stone","word"],"peopleInVerse":[]},"9":{"text":"But ye are a chosen generation, a royal priesthood, an holy nation, a peculiar people; that ye should shew forth the praises of him who hath called you out of darkness into his marvellous light:","ref":"1 Peter 2:9","synthesized":"But you are a chosen people, a royal priesthood, a holy nation, a people for God’s own possession, to proclaim the virtues of Him who called you out of darkness into His marvelous light.","sources":{"KJV":{"text":"But ye are a chosen generation, a royal priesthood, an holy nation, a peculiar people; that ye should shew forth the praises of him who hath called you out of darkness into his marvellous light:"},"BSB":{"text":"But you are a chosen people, a royal priesthood, a holy nation, a people for God’s own possession, to proclaim the virtues of Him who called you out of darkness into His marvelous light."}},"definableWords":["people","holy","nation","God","darkness","light"],"peopleInVerse":[]},"10":{"text":"Which in time past were not a people, but are now the people of God: which had not obtained mercy, but now have obtained mercy.","ref":"1 Peter 2:10","synthesized":"Once you were not a people, but now you are the people of God; once you had not received mercy, but now you have received mercy.","sources":{"KJV":{"text":"Which in time past were not a people, but are now the people of God: which had not obtained mercy, but now have obtained mercy."},"BSB":{"text":"Once you were not a people, but now you are the people of God; once you had not received mercy, but now you have received mercy."}},"definableWords":["people","God","mercy"],"peopleInVerse":[]},"11":{"text":"Dearly beloved, I beseech you as strangers and pilgrims, abstain from fleshly lusts, which war against the soul;","ref":"1 Peter 2:11","synthesized":"Beloved, I urge you, as foreigners and exiles, to abstain from the desires of the flesh, which war against your soul.","sources":{"KJV":{"text":"Dearly beloved, I beseech you as strangers and pilgrims, abstain from fleshly lusts, which war against the soul;"},"BSB":{"text":"Beloved, I urge you, as foreigners and exiles, to abstain from the desires of the flesh, which war against your soul."}},"definableWords":["flesh","soul"],"peopleInVerse":[]},"12":{"text":"Having your conversation honest among the Gentiles: that, whereas they speak against you as evildoers, they may by your good works, which they shall behold, glorify God in the day of visitation.","ref":"1 Peter 2:12","synthesized":"Conduct yourselves with such honor among the Gentiles that, though they slander you as evildoers, they may see your good deeds and glorify God on the day He visits us.","sources":{"KJV":{"text":"Having your conversation honest among the Gentiles: that, whereas they speak against you as evildoers, they may by your good works, which they shall behold, glorify God in the day of visitation."},"BSB":{"text":"Conduct yourselves with such honor among the Gentiles that, though they slander you as evildoers, they may see your good deeds and glorify God on the day He visits us."}},"definableWords":["see","good","God","day"],"peopleInVerse":[]},"13":{"text":"Submit yourselves to every ordinance of man for the Lord’s sake: whether it be to the king, as supreme;","ref":"1 Peter 2:13","synthesized":"Submit yourselves for the Lord’s sake to every human institution, whether to the king as the supreme authority,","sources":{"KJV":{"text":"Submit yourselves to every ordinance of man for the Lord’s sake: whether it be to the king, as supreme;"},"BSB":{"text":"Submit yourselves for the Lord’s sake to every human institution, whether to the king as the supreme authority,"}},"definableWords":["Lord","king"],"peopleInVerse":[]},"14":{"text":"Or unto governors, as unto them that are sent by him for the punishment of evildoers, and for the praise of them that do well.","ref":"1 Peter 2:14","synthesized":"or to governors as those sent by him to punish those who do wrong and to praise those who do right.","sources":{"KJV":{"text":"Or unto governors, as unto them that are sent by him for the punishment of evildoers, and for the praise of them that do well."},"BSB":{"text":"or to governors as those sent by him to punish those who do wrong and to praise those who do right."}},"definableWords":["or","praise"],"peopleInVerse":[]},"15":{"text":"For so is the will of God, that with well doing ye may put to silence the ignorance of foolish men:","ref":"1 Peter 2:15","synthesized":"For it is God’s will that by doing good you should silence the ignorance of foolish men.","sources":{"KJV":{"text":"For so is the will of God, that with well doing ye may put to silence the ignorance of foolish men:"},"BSB":{"text":"For it is God’s will that by doing good you should silence the ignorance of foolish men."}},"definableWords":["God","good","men"],"peopleInVerse":[]},"16":{"text":"As free, and not using your liberty for a cloke of maliciousness, but as the servants of God.","ref":"1 Peter 2:16","synthesized":"Live in freedom, but do not use your freedom as a cover-up for evil; live as servants of God.","sources":{"KJV":{"text":"As free, and not using your liberty for a cloke of maliciousness, but as the servants of God."},"BSB":{"text":"Live in freedom, but do not use your freedom as a cover-up for evil; live as servants of God."}},"definableWords":["live","evil","servants","God"],"peopleInVerse":[]},"17":{"text":"Honour all men. Love the brotherhood. Fear God. Honour the king.","ref":"1 Peter 2:17","synthesized":"Treat everyone with high regard: Love the brotherhood of believers, fear God, honor the king.","sources":{"KJV":{"text":"Honour all men. Love the brotherhood. Fear God. Honour the king."},"BSB":{"text":"Treat everyone with high regard: Love the brotherhood of believers, fear God, honor the king."}},"definableWords":["love","fear","God","king"],"peopleInVerse":[]},"18":{"text":"Servants, be subject to your masters with all fear; not only to the good and gentle, but also to the froward.","ref":"1 Peter 2:18","synthesized":"Servants, submit yourselves to your masters with all respect, not only to those who are good and gentle, but even to those who are unreasonable.","sources":{"KJV":{"text":"Servants, be subject to your masters with all fear; not only to the good and gentle, but also to the froward."},"BSB":{"text":"Servants, submit yourselves to your masters with all respect, not only to those who are good and gentle, but even to those who are unreasonable."}},"definableWords":["servants","good"],"peopleInVerse":[]},"19":{"text":"For this is thankworthy, if a man for conscience toward God endure grief, suffering wrongfully.","ref":"1 Peter 2:19","synthesized":"For if anyone endures the pain of unjust suffering because he is conscious of God, this is to be commended.","sources":{"KJV":{"text":"For this is thankworthy, if a man for conscience toward God endure grief, suffering wrongfully."},"BSB":{"text":"For if anyone endures the pain of unjust suffering because he is conscious of God, this is to be commended."}},"definableWords":["God"],"peopleInVerse":[]},"20":{"text":"For what glory is it, if, when ye be buffeted for your faults, ye shall take it patiently? but if, when ye do well, and suffer for it, ye take it patiently, this is acceptable with God.","ref":"1 Peter 2:20","synthesized":"How is it to your credit if you are beaten for doing wrong and you endure it? But if you suffer for doing good and you endure it, this is commendable before God.","sources":{"KJV":{"text":"For what glory is it, if, when ye be buffeted for your faults, ye shall take it patiently? but if, when ye do well, and suffer for it, ye take it patiently, this is acceptable with God."},"BSB":{"text":"How is it to your credit if you are beaten for doing wrong and you endure it? But if you suffer for doing good and you endure it, this is commendable before God."}},"definableWords":["good","God"],"peopleInVerse":[]},"21":{"text":"For even hereunto were ye called: because Christ also suffered for us, leaving us an example, that ye should follow his steps:","ref":"1 Peter 2:21","synthesized":"For to this you were called, because Christ also suffered for you, leaving you an example, that you should follow in His footsteps:","sources":{"KJV":{"text":"For even hereunto were ye called: because Christ also suffered for us, leaving us an example, that ye should follow his steps:"},"BSB":{"text":"For to this you were called, because Christ also suffered for you, leaving you an example, that you should follow in His footsteps:"}},"definableWords":["Christ"],"peopleInVerse":[]},"22":{"text":"Who did no sin, neither was guile found in his mouth:","ref":"1 Peter 2:22","synthesized":"“He committed no sin, and no deceit was found in His mouth.”","sources":{"KJV":{"text":"Who did no sin, neither was guile found in his mouth:"},"BSB":{"text":"“He committed no sin, and no deceit was found in His mouth.”"}},"definableWords":["sin"],"peopleInVerse":[]},"23":{"text":"Who, when he was reviled, reviled not again; when he suffered, he threatened not; but committed himself to him that judgeth righteously:","ref":"1 Peter 2:23","synthesized":"When they heaped abuse on Him, He did not retaliate; when He suffered, He made no threats, but entrusted Himself to Him who judges justly.","sources":{"KJV":{"text":"Who, when he was reviled, reviled not again; when he suffered, he threatened not; but committed himself to him that judgeth righteously:"},"BSB":{"text":"When they heaped abuse on Him, He did not retaliate; when He suffered, He made no threats, but entrusted Himself to Him who judges justly."}},"definableWords":["made"],"peopleInVerse":[]},"24":{"text":"Who his own self bare our sins in his own body on the tree, that we, being dead to sins, should live unto righteousness: by whose stripes ye were healed.","ref":"1 Peter 2:24","synthesized":"He Himself bore our sins in His body on the tree, so that we might die to sin and live to righteousness. “By His stripes you are healed.”","sources":{"KJV":{"text":"Who his own self bare our sins in his own body on the tree, that we, being dead to sins, should live unto righteousness: by whose stripes ye were healed."},"BSB":{"text":"He Himself bore our sins in His body on the tree, so that we might die to sin and live to righteousness. “By His stripes you are healed.”"}},"definableWords":["tree","die","sin","live","righteousness"],"peopleInVerse":[]},"25":{"text":"For ye were as sheep going astray; but are now returned unto the Shepherd and Bishop of your souls.","ref":"1 Peter 2:25","synthesized":"For “you were like sheep going astray,” but now you have returned to the Shepherd and Overseer of your souls.","sources":{"KJV":{"text":"For ye were as sheep going astray; but are now returned unto the Shepherd and Bishop of your souls."},"BSB":{"text":"For “you were like sheep going astray,” but now you have returned to the Shepherd and Overseer of your souls."}},"definableWords":["shepherd"],"peopleInVerse":[]}}},"3":{"chapter":"3","title":"HUSBANDS AND WIVES — SUFFERING FOR RIGHTEOUSNESS","verses":{"1":{"text":"Likewise, ye wives, be in subjection to your own husbands; that, if any obey not the word, they also may without the word be won by the conversation of the wives;","ref":"1 Peter 3:1","synthesized":"Wives, in the same way, submit yourselves to your husbands, so that even if they refuse to believe the word, they will be won over without words by the behavior of their wives","sources":{"KJV":{"text":"Likewise, ye wives, be in subjection to your own husbands; that, if any obey not the word, they also may without the word be won by the conversation of the wives;"},"BSB":{"text":"Wives, in the same way, submit yourselves to your husbands, so that even if they refuse to believe the word, they will be won over without words by the behavior of their wives"}},"definableWords":["way","word"],"peopleInVerse":[]},"2":{"text":"While they behold your chaste conversation coupled with fear.","ref":"1 Peter 3:2","synthesized":"when they see your pure and reverent demeanor.","sources":{"KJV":{"text":"While they behold your chaste conversation coupled with fear."},"BSB":{"text":"when they see your pure and reverent demeanor."}},"definableWords":["see"],"peopleInVerse":[]},"3":{"text":"Whose adorning let it not be that outward adorning of plaiting the hair, and of wearing of gold, or of putting on of apparel;","ref":"1 Peter 3:3","synthesized":"Your beauty should not come from outward adornment, such as braided hair or gold jewelry or fine clothes,","sources":{"KJV":{"text":"Whose adorning let it not be that outward adorning of plaiting the hair, and of wearing of gold, or of putting on of apparel;"},"BSB":{"text":"Your beauty should not come from outward adornment, such as braided hair or gold jewelry or fine clothes,"}},"definableWords":["or"],"peopleInVerse":[]},"4":{"text":"But let it be the hidden man of the heart, in that which is not corruptible, even the ornament of a meek and quiet spirit, which is in the sight of God of great price.","ref":"1 Peter 3:4","synthesized":"but from the inner disposition of your heart, the unfading beauty of a gentle and quiet spirit, which is precious in God’s sight.","sources":{"KJV":{"text":"But let it be the hidden man of the heart, in that which is not corruptible, even the ornament of a meek and quiet spirit, which is in the sight of God of great price."},"BSB":{"text":"but from the inner disposition of your heart, the unfading beauty of a gentle and quiet spirit, which is precious in God’s sight."}},"definableWords":["heart","spirit","God"],"peopleInVerse":[]},"5":{"text":"For after this manner in the old time the holy women also, who trusted in God, adorned themselves, being in subjection unto their own husbands:","ref":"1 Peter 3:5","synthesized":"For this is how the holy women of the past adorned themselves. They put their hope in God and were submissive to their husbands,","sources":{"KJV":{"text":"For after this manner in the old time the holy women also, who trusted in God, adorned themselves, being in subjection unto their own husbands:"},"BSB":{"text":"For this is how the holy women of the past adorned themselves. They put their hope in God and were submissive to their husbands,"}},"definableWords":["holy","women","hope","God"],"peopleInVerse":[]},"6":{"text":"Even as Sara obeyed Abraham, calling him lord: whose daughters ye are, as long as ye do well, and are not afraid with any amazement.","ref":"1 Peter 3:6","synthesized":"just as Sarah obeyed Abraham and called him lord. And you are her children if you do what is right and refuse to give way to fear.","sources":{"KJV":{"text":"Even as Sara obeyed Abraham, calling him lord: whose daughters ye are, as long as ye do well, and are not afraid with any amazement."},"BSB":{"text":"just as Sarah obeyed Abraham and called him lord. And you are her children if you do what is right and refuse to give way to fear."}},"definableWords":["Sarah","Abraham","Lord","way","fear"],"peopleInVerse":["Sarah","Abraham"]},"7":{"text":"Likewise, ye husbands, dwell with them according to knowledge, giving honour unto the wife, as unto the weaker vessel, and as being heirs together of the grace of life; that your prayers be not hindered.","ref":"1 Peter 3:7","synthesized":"Husbands, in the same way, treat your wives with consideration as a delicate vessel, and with honor as fellow heirs of the gracious gift of life, so that your prayers will not be hindered.","sources":{"KJV":{"text":"Likewise, ye husbands, dwell with them according to knowledge, giving honour unto the wife, as unto the weaker vessel, and as being heirs together of the grace of life; that your prayers be not hindered."},"BSB":{"text":"Husbands, in the same way, treat your wives with consideration as a delicate vessel, and with honor as fellow heirs of the gracious gift of life, so that your prayers will not be hindered."}},"definableWords":["way","life"],"peopleInVerse":[]},"8":{"text":"Finally, be ye all of one mind, having compassion one of another, love as brethren, be pitiful, be courteous:","ref":"1 Peter 3:8","synthesized":"Finally, all of you, be like-minded and sympathetic, love as brothers, be tenderhearted and humble.","sources":{"KJV":{"text":"Finally, be ye all of one mind, having compassion one of another, love as brethren, be pitiful, be courteous:"},"BSB":{"text":"Finally, all of you, be like-minded and sympathetic, love as brothers, be tenderhearted and humble."}},"definableWords":["love"],"peopleInVerse":[]},"9":{"text":"Not rendering evil for evil, or railing for railing: but contrariwise blessing; knowing that ye are thereunto called, that ye should inherit a blessing.","ref":"1 Peter 3:9","synthesized":"Do not repay evil with evil or insult with insult, but with blessing, because to this you were called so that you may inherit a blessing.","sources":{"KJV":{"text":"Not rendering evil for evil, or railing for railing: but contrariwise blessing; knowing that ye are thereunto called, that ye should inherit a blessing."},"BSB":{"text":"Do not repay evil with evil or insult with insult, but with blessing, because to this you were called so that you may inherit a blessing."}},"definableWords":["evil","or","blessing","inherit"],"peopleInVerse":[]},"10":{"text":"For he that will love life, and see good days, let him refrain his tongue from evil, and his lips that they speak no guile:","ref":"1 Peter 3:10","synthesized":"For,  “Whoever would love life and see good days must keep his tongue from evil and his lips from deceitful speech.","sources":{"KJV":{"text":"For he that will love life, and see good days, let him refrain his tongue from evil, and his lips that they speak no guile:"},"BSB":{"text":"For,  “Whoever would love life and see good days must keep his tongue from evil and his lips from deceitful speech."}},"definableWords":["love","life","see","good","days","keep","evil"],"peopleInVerse":[]},"11":{"text":"Let him eschew evil, and do good; let him seek peace, and ensue it.","ref":"1 Peter 3:11","synthesized":"He must turn from evil and do good; he must seek peace and pursue it.","sources":{"KJV":{"text":"Let him eschew evil, and do good; let him seek peace, and ensue it."},"BSB":{"text":"He must turn from evil and do good; he must seek peace and pursue it."}},"definableWords":["evil","good","seek","peace"],"peopleInVerse":[]},"12":{"text":"For the eyes of the Lord are over the righteous, and his ears are open unto their prayers: but the face of the Lord is against them that do evil.","ref":"1 Peter 3:12","synthesized":"For the eyes of the Lord are on the righteous, and His ears are inclined to their prayer. But the face of the Lord is against those who do evil.”","sources":{"KJV":{"text":"For the eyes of the Lord are over the righteous, and his ears are open unto their prayers: but the face of the Lord is against them that do evil."},"BSB":{"text":"For the eyes of the Lord are on the righteous, and His ears are inclined to their prayer. But the face of the Lord is against those who do evil.”"}},"definableWords":["Lord","righteous","prayer","evil"],"peopleInVerse":[]},"13":{"text":"And who is he that will harm you, if ye be followers of that which is good?","ref":"1 Peter 3:13","synthesized":"Who can harm you if you are zealous for what is good?","sources":{"KJV":{"text":"And who is he that will harm you, if ye be followers of that which is good?"},"BSB":{"text":"Who can harm you if you are zealous for what is good?"}},"definableWords":["good"],"peopleInVerse":[]},"14":{"text":"But and if ye suffer for righteousness’ sake, happy are ye: and be not afraid of their terror, neither be troubled;","ref":"1 Peter 3:14","synthesized":"But even if you should suffer for what is right, you are blessed. “Do not fear what they fear; do not be shaken.”","sources":{"KJV":{"text":"But and if ye suffer for righteousness’ sake, happy are ye: and be not afraid of their terror, neither be troubled;"},"BSB":{"text":"But even if you should suffer for what is right, you are blessed. “Do not fear what they fear; do not be shaken.”"}},"definableWords":["blessed","fear"],"peopleInVerse":[]},"15":{"text":"But sanctify the Lord God in your hearts: and be ready always to give an answer to every man that asketh you a reason of the hope that is in you with meekness and fear:","ref":"1 Peter 3:15","synthesized":"But in your hearts sanctify Christ as Lord. Always be prepared to give a defense to everyone who asks you the reason for the hope that is in you. But respond with gentleness and respect,","sources":{"KJV":{"text":"But sanctify the Lord God in your hearts: and be ready always to give an answer to every man that asketh you a reason of the hope that is in you with meekness and fear:"},"BSB":{"text":"But in your hearts sanctify Christ as Lord. Always be prepared to give a defense to everyone who asks you the reason for the hope that is in you. But respond with gentleness and respect,"}},"definableWords":["Christ","Lord","hope"],"peopleInVerse":[]},"16":{"text":"Having a good conscience; that, whereas they speak evil of you, as of evildoers, they may be ashamed that falsely accuse your good conversation in Christ.","ref":"1 Peter 3:16","synthesized":"keeping a clear conscience, so that those who slander you may be put to shame by your good behavior in Christ.","sources":{"KJV":{"text":"Having a good conscience; that, whereas they speak evil of you, as of evildoers, they may be ashamed that falsely accuse your good conversation in Christ."},"BSB":{"text":"keeping a clear conscience, so that those who slander you may be put to shame by your good behavior in Christ."}},"definableWords":["good","Christ"],"peopleInVerse":[]},"17":{"text":"For it is better, if the will of God be so, that ye suffer for well doing, than for evil doing.","ref":"1 Peter 3:17","synthesized":"For it is better, if it is God’s will, to suffer for doing good than for doing evil.","sources":{"KJV":{"text":"For it is better, if the will of God be so, that ye suffer for well doing, than for evil doing."},"BSB":{"text":"For it is better, if it is God’s will, to suffer for doing good than for doing evil."}},"definableWords":["God","good","evil"],"peopleInVerse":[]},"18":{"text":"For Christ also hath once suffered for sins, the just for the unjust, that he might bring us to God, being put to death in the flesh, but quickened by the Spirit:","ref":"1 Peter 3:18","synthesized":"For Christ also suffered for sins once for all, the righteous for the unrighteous, to bring you to God. He was put to death in the body but made alive in the Spirit,","sources":{"KJV":{"text":"For Christ also hath once suffered for sins, the just for the unjust, that he might bring us to God, being put to death in the flesh, but quickened by the Spirit:"},"BSB":{"text":"For Christ also suffered for sins once for all, the righteous for the unrighteous, to bring you to God. He was put to death in the body but made alive in the Spirit,"}},"definableWords":["Christ","righteous","God","death","made","Spirit"],"peopleInVerse":[]},"19":{"text":"By which also he went and preached unto the spirits in prison;","ref":"1 Peter 3:19","synthesized":"in whom He also went and preached to the spirits in prison","sources":{"KJV":{"text":"By which also he went and preached unto the spirits in prison;"},"BSB":{"text":"in whom He also went and preached to the spirits in prison"}},"definableWords":[],"peopleInVerse":[]},"20":{"text":"Which sometime were disobedient, when once the longsuffering of God waited in the days of Noah, while the ark was a preparing, wherein few, that is, eight souls were saved by water.","ref":"1 Peter 3:20","synthesized":"who disobeyed long ago when God waited patiently in the days of Noah while the ark was being built.  In the ark a few people, only eight souls, were saved through water.","sources":{"KJV":{"text":"Which sometime were disobedient, when once the longsuffering of God waited in the days of Noah, while the ark was a preparing, wherein few, that is, eight souls were saved by water."},"BSB":{"text":"who disobeyed long ago when God waited patiently in the days of Noah while the ark was being built.  In the ark a few people, only eight souls, were saved through water."}},"definableWords":["God","days","Noah","ark","people","water"],"peopleInVerse":["Noah"]},"21":{"text":"The like figure whereunto even baptism doth also now save us (not the putting away of the filth of the flesh, but the answer of a good conscience toward God,) by the resurrection of Jesus Christ:","ref":"1 Peter 3:21","synthesized":"And this water symbolizes the baptism that now saves you also—not the removal of dirt from the body, but the pledge of a clear conscience toward God—through the resurrection of Jesus Christ,","sources":{"KJV":{"text":"The like figure whereunto even baptism doth also now save us (not the putting away of the filth of the flesh, but the answer of a good conscience toward God,) by the resurrection of Jesus Christ:"},"BSB":{"text":"And this water symbolizes the baptism that now saves you also—not the removal of dirt from the body, but the pledge of a clear conscience toward God—through the resurrection of Jesus Christ,"}},"definableWords":["water","baptism","God","resurrection","Christ"],"peopleInVerse":["Jesus"]},"22":{"text":"Who is gone into heaven, and is on the right hand of God; angels and authorities and powers being made subject unto him.","ref":"1 Peter 3:22","synthesized":"who has gone into heaven and is at the right hand of God, with angels, authorities, and powers subject to Him.","sources":{"KJV":{"text":"Who is gone into heaven, and is on the right hand of God; angels and authorities and powers being made subject unto him."},"BSB":{"text":"who has gone into heaven and is at the right hand of God, with angels, authorities, and powers subject to Him."}},"definableWords":["heaven","God"],"peopleInVerse":[]}}},"4":{"chapter":"4","title":"GIRD UP THE LOINS OF YOUR MINDS","verses":{"1":{"text":"Forasmuch then as Christ hath suffered for us in the flesh, arm yourselves likewise with the same mind: for he that hath suffered in the flesh hath ceased from sin;","ref":"1 Peter 4:1","synthesized":"Therefore, since Christ suffered in His body, arm yourselves with the same resolve, because anyone who has suffered in his body is done with sin.","sources":{"KJV":{"text":"Forasmuch then as Christ hath suffered for us in the flesh, arm yourselves likewise with the same mind: for he that hath suffered in the flesh hath ceased from sin;"},"BSB":{"text":"Therefore, since Christ suffered in His body, arm yourselves with the same resolve, because anyone who has suffered in his body is done with sin."}},"definableWords":["Christ","sin"],"peopleInVerse":[]},"2":{"text":"That he no longer should live the rest of his time in the flesh to the lusts of men, but to the will of God.","ref":"1 Peter 4:2","synthesized":"Consequently, he does not live out his remaining time on earth for human passions, but for the will of God.","sources":{"KJV":{"text":"That he no longer should live the rest of his time in the flesh to the lusts of men, but to the will of God."},"BSB":{"text":"Consequently, he does not live out his remaining time on earth for human passions, but for the will of God."}},"definableWords":["live","earth","God"],"peopleInVerse":[]},"3":{"text":"For the time past of our life may suffice us to have wrought the will of the Gentiles, when we walked in lasciviousness, lusts, excess of wine, revellings, banquetings, and abominable idolatries:","ref":"1 Peter 4:3","synthesized":"For you have spent enough time in the past carrying out the same desires as the Gentiles: living in debauchery, lust, drunkenness, orgies, carousing, and detestable idolatry.","sources":{"KJV":{"text":"For the time past of our life may suffice us to have wrought the will of the Gentiles, when we walked in lasciviousness, lusts, excess of wine, revellings, banquetings, and abominable idolatries:"},"BSB":{"text":"For you have spent enough time in the past carrying out the same desires as the Gentiles: living in debauchery, lust, drunkenness, orgies, carousing, and detestable idolatry."}},"definableWords":["living"],"peopleInVerse":[]},"4":{"text":"Wherein they think it strange that ye run not with them to the same excess of riot, speaking evil of you:","ref":"1 Peter 4:4","synthesized":"Because of this, they consider it strange of you not to plunge with them into the same flood of reckless indiscretion, and they heap abuse on you.","sources":{"KJV":{"text":"Wherein they think it strange that ye run not with them to the same excess of riot, speaking evil of you:"},"BSB":{"text":"Because of this, they consider it strange of you not to plunge with them into the same flood of reckless indiscretion, and they heap abuse on you."}},"definableWords":["flood"],"peopleInVerse":[]},"5":{"text":"Who shall give account to him that is ready to judge the quick and the dead.","ref":"1 Peter 4:5","synthesized":"But they will have to give an account to Him who is ready to judge the living and the dead.","sources":{"KJV":{"text":"Who shall give account to him that is ready to judge the quick and the dead."},"BSB":{"text":"But they will have to give an account to Him who is ready to judge the living and the dead."}},"definableWords":["living"],"peopleInVerse":[]},"6":{"text":"For for this cause was the gospel preached also to them that are dead, that they might be judged according to men in the flesh, but live according to God in the spirit.","ref":"1 Peter 4:6","synthesized":"That is why the gospel was preached even to those who are now dead, so that they might be judged as men in the flesh, but live according to God in the spirit.","sources":{"KJV":{"text":"For for this cause was the gospel preached also to them that are dead, that they might be judged according to men in the flesh, but live according to God in the spirit."},"BSB":{"text":"That is why the gospel was preached even to those who are now dead, so that they might be judged as men in the flesh, but live according to God in the spirit."}},"definableWords":["gospel","men","flesh","live","God","spirit"],"peopleInVerse":[]},"7":{"text":"But the end of all things is at hand: be ye therefore sober, and watch unto prayer.","ref":"1 Peter 4:7","synthesized":"The end of all things is near. Therefore be clear-minded and sober, so that you can pray.","sources":{"KJV":{"text":"But the end of all things is at hand: be ye therefore sober, and watch unto prayer."},"BSB":{"text":"The end of all things is near. Therefore be clear-minded and sober, so that you can pray."}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"And above all things have fervent charity among yourselves: for charity shall cover the multitude of sins.","ref":"1 Peter 4:8","synthesized":"Above all, love one another deeply, because love covers over a multitude of sins.","sources":{"KJV":{"text":"And above all things have fervent charity among yourselves: for charity shall cover the multitude of sins."},"BSB":{"text":"Above all, love one another deeply, because love covers over a multitude of sins."}},"definableWords":["love","one"],"peopleInVerse":[]},"9":{"text":"Use hospitality one to another without grudging.","ref":"1 Peter 4:9","synthesized":"Show hospitality to one another without complaining.","sources":{"KJV":{"text":"Use hospitality one to another without grudging."},"BSB":{"text":"Show hospitality to one another without complaining."}},"definableWords":["one"],"peopleInVerse":[]},"10":{"text":"As every man hath received the gift, even so minister the same one to another, as good stewards of the manifold grace of God.","ref":"1 Peter 4:10","synthesized":"As good stewards of the manifold grace of God, each of you should use whatever gift he has received to serve one another.","sources":{"KJV":{"text":"As every man hath received the gift, even so minister the same one to another, as good stewards of the manifold grace of God."},"BSB":{"text":"As good stewards of the manifold grace of God, each of you should use whatever gift he has received to serve one another."}},"definableWords":["good","grace","God","one"],"peopleInVerse":[]},"11":{"text":"If any man speak, let him speak as the oracles of God; if any man minister, let him do it as of the ability which God giveth: that God in all things may be glorified through Jesus Christ, to whom be praise and dominion for ever and ever. Amen.","ref":"1 Peter 4:11","synthesized":"If anyone speaks, he should speak as one conveying the words of God. If anyone serves, he should serve with the strength God provides, so that in all things God may be glorified through Jesus Christ, to whom be the glory and the power forever and ever. Amen.","sources":{"KJV":{"text":"If any man speak, let him speak as the oracles of God; if any man minister, let him do it as of the ability which God giveth: that God in all things may be glorified through Jesus Christ, to whom be praise and dominion for ever and ever. Amen."},"BSB":{"text":"If anyone speaks, he should speak as one conveying the words of God. If anyone serves, he should serve with the strength God provides, so that in all things God may be glorified through Jesus Christ, to whom be the glory and the power forever and ever. Amen."}},"definableWords":["one","God","Christ","glory"],"peopleInVerse":["Jesus"]},"12":{"text":"Beloved, think it not strange concerning the fiery trial which is to try you, as though some strange thing happened unto you:","ref":"1 Peter 4:12","synthesized":"Beloved, do not be surprised at the fiery trial that has come upon you, as though something strange were happening to you.","sources":{"KJV":{"text":"Beloved, think it not strange concerning the fiery trial which is to try you, as though some strange thing happened unto you:"},"BSB":{"text":"Beloved, do not be surprised at the fiery trial that has come upon you, as though something strange were happening to you."}},"definableWords":[],"peopleInVerse":[]},"13":{"text":"But rejoice, inasmuch as ye are partakers of Christ’s sufferings; that, when his glory shall be revealed, ye may be glad also with exceeding joy.","ref":"1 Peter 4:13","synthesized":"But rejoice that you share in the sufferings of Christ, so that you may be overjoyed at the revelation of His glory.","sources":{"KJV":{"text":"But rejoice, inasmuch as ye are partakers of Christ’s sufferings; that, when his glory shall be revealed, ye may be glad also with exceeding joy."},"BSB":{"text":"But rejoice that you share in the sufferings of Christ, so that you may be overjoyed at the revelation of His glory."}},"definableWords":["Christ","glory"],"peopleInVerse":[]},"14":{"text":"If ye be reproached for the name of Christ, happy are ye; for the spirit of glory and of God resteth upon you: on their part he is evil spoken of, but on your part he is glorified.","ref":"1 Peter 4:14","synthesized":"If you are insulted for the name of Christ, you are blessed, because the Spirit of glory and of God rests on you.","sources":{"KJV":{"text":"If ye be reproached for the name of Christ, happy are ye; for the spirit of glory and of God resteth upon you: on their part he is evil spoken of, but on your part he is glorified."},"BSB":{"text":"If you are insulted for the name of Christ, you are blessed, because the Spirit of glory and of God rests on you."}},"definableWords":["name","Christ","blessed","Spirit","glory","God"],"peopleInVerse":[]},"15":{"text":"But let none of you suffer as a murderer, or as a thief, or as an evildoer, or as a busybody in other men’s matters.","ref":"1 Peter 4:15","synthesized":"Indeed, none of you should suffer as a murderer or thief or wrongdoer, or even as a meddler.","sources":{"KJV":{"text":"But let none of you suffer as a murderer, or as a thief, or as an evildoer, or as a busybody in other men’s matters."},"BSB":{"text":"Indeed, none of you should suffer as a murderer or thief or wrongdoer, or even as a meddler."}},"definableWords":["or"],"peopleInVerse":[]},"16":{"text":"Yet if any man suffer as a Christian, let him not be ashamed; but let him glorify God on this behalf.","ref":"1 Peter 4:16","synthesized":"But if you suffer as a Christian, do not be ashamed, but glorify God that you bear that name.","sources":{"KJV":{"text":"Yet if any man suffer as a Christian, let him not be ashamed; but let him glorify God on this behalf."},"BSB":{"text":"But if you suffer as a Christian, do not be ashamed, but glorify God that you bear that name."}},"definableWords":["God","name"],"peopleInVerse":[]},"17":{"text":"For the time is come that judgment must begin at the house of God: and if it first begin at us, what shall the end be of them that obey not the gospel of God?","ref":"1 Peter 4:17","synthesized":"For it is time for judgment to begin with the family of God; and if it begins with us, what will the outcome be for those who disobey the gospel of God?","sources":{"KJV":{"text":"For the time is come that judgment must begin at the house of God: and if it first begin at us, what shall the end be of them that obey not the gospel of God?"},"BSB":{"text":"For it is time for judgment to begin with the family of God; and if it begins with us, what will the outcome be for those who disobey the gospel of God?"}},"definableWords":["judgment","begin","family","God","gospel"],"peopleInVerse":[]},"18":{"text":"And if the righteous scarcely be saved, where shall the ungodly and the sinner appear?","ref":"1 Peter 4:18","synthesized":"And,  “If it is hard for the righteous to be saved, what will become of the ungodly and the sinner?”","sources":{"KJV":{"text":"And if the righteous scarcely be saved, where shall the ungodly and the sinner appear?"},"BSB":{"text":"And,  “If it is hard for the righteous to be saved, what will become of the ungodly and the sinner?”"}},"definableWords":["righteous"],"peopleInVerse":[]},"19":{"text":"Wherefore let them that suffer according to the will of God commit the keeping of their souls to him in well doing, as unto a faithful Creator.","ref":"1 Peter 4:19","synthesized":"So then, those who suffer according to God’s will should entrust their souls to their faithful Creator and continue to do good.","sources":{"KJV":{"text":"Wherefore let them that suffer according to the will of God commit the keeping of their souls to him in well doing, as unto a faithful Creator."},"BSB":{"text":"So then, those who suffer according to God’s will should entrust their souls to their faithful Creator and continue to do good."}},"definableWords":["God","good"],"peopleInVerse":[]}}},"5":{"chapter":"5","title":"CAST ALL YOUR CARE ON HIM","verses":{"1":{"text":"The elders which are among you I exhort, who am also an elder, and a witness of the sufferings of Christ, and also a partaker of the glory that shall be revealed:","ref":"1 Peter 5:1","synthesized":"As a fellow elder, a witness of Christ’s sufferings, and a partaker of the glory to be revealed, I appeal to the elders among you:","sources":{"KJV":{"text":"The elders which are among you I exhort, who am also an elder, and a witness of the sufferings of Christ, and also a partaker of the glory that shall be revealed:"},"BSB":{"text":"As a fellow elder, a witness of Christ’s sufferings, and a partaker of the glory to be revealed, I appeal to the elders among you:"}},"definableWords":["elder","Christ","glory"],"peopleInVerse":[]},"2":{"text":"Feed the flock of God which is among you, taking the oversight thereof, not by constraint, but willingly; not for filthy lucre, but of a ready mind;","ref":"1 Peter 5:2","synthesized":"Be shepherds of God’s flock that is among you, watching over them not out of compulsion, but because it is God’s will; not out of greed, but out of eagerness;","sources":{"KJV":{"text":"Feed the flock of God which is among you, taking the oversight thereof, not by constraint, but willingly; not for filthy lucre, but of a ready mind;"},"BSB":{"text":"Be shepherds of God’s flock that is among you, watching over them not out of compulsion, but because it is God’s will; not out of greed, but out of eagerness;"}},"definableWords":["God"],"peopleInVerse":[]},"3":{"text":"Neither as being lords over God’s heritage, but being ensamples to the flock.","ref":"1 Peter 5:3","synthesized":"not lording it over those entrusted to you, but being examples to the flock.","sources":{"KJV":{"text":"Neither as being lords over God’s heritage, but being ensamples to the flock."},"BSB":{"text":"not lording it over those entrusted to you, but being examples to the flock."}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"And when the chief Shepherd shall appear, ye shall receive a crown of glory that fadeth not away.","ref":"1 Peter 5:4","synthesized":"And when the Chief Shepherd appears, you will receive the crown of glory that will never fade away.","sources":{"KJV":{"text":"And when the chief Shepherd shall appear, ye shall receive a crown of glory that fadeth not away."},"BSB":{"text":"And when the Chief Shepherd appears, you will receive the crown of glory that will never fade away."}},"definableWords":["shepherd","crown","glory"],"peopleInVerse":[]},"5":{"text":"Likewise, ye younger, submit yourselves unto the elder. Yea, all of you be subject one to another, and be clothed with humility: for God resisteth the proud, and giveth grace to the humble.","ref":"1 Peter 5:5","synthesized":"Young men, in the same way, submit yourselves to your elders. And all of you, clothe yourselves with humility toward one another, because,  “God opposes the proud, but gives grace to the humble.”","sources":{"KJV":{"text":"Likewise, ye younger, submit yourselves unto the elder. Yea, all of you be subject one to another, and be clothed with humility: for God resisteth the proud, and giveth grace to the humble."},"BSB":{"text":"Young men, in the same way, submit yourselves to your elders. And all of you, clothe yourselves with humility toward one another, because,  “God opposes the proud, but gives grace to the humble.”"}},"definableWords":["men","way","one","God","grace"],"peopleInVerse":[]},"6":{"text":"Humble yourselves therefore under the mighty hand of God, that he may exalt you in due time:","ref":"1 Peter 5:6","synthesized":"Humble yourselves, therefore, under God’s mighty hand, so that in due time He may exalt you.","sources":{"KJV":{"text":"Humble yourselves therefore under the mighty hand of God, that he may exalt you in due time:"},"BSB":{"text":"Humble yourselves, therefore, under God’s mighty hand, so that in due time He may exalt you."}},"definableWords":["God","mighty"],"peopleInVerse":[]},"7":{"text":"Casting all your care upon him; for he careth for you.","ref":"1 Peter 5:7","synthesized":"Cast all your anxiety on Him, because He cares for you.","sources":{"KJV":{"text":"Casting all your care upon him; for he careth for you."},"BSB":{"text":"Cast all your anxiety on Him, because He cares for you."}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"Be sober, be vigilant; because your adversary the devil, as a roaring lion, walketh about, seeking whom he may devour:","ref":"1 Peter 5:8","synthesized":"Be sober-minded and alert. Your adversary the devil prowls around like a roaring lion, seeking someone to devour.","sources":{"KJV":{"text":"Be sober, be vigilant; because your adversary the devil, as a roaring lion, walketh about, seeking whom he may devour:"},"BSB":{"text":"Be sober-minded and alert. Your adversary the devil prowls around like a roaring lion, seeking someone to devour."}},"definableWords":["devil","lion"],"peopleInVerse":[]},"9":{"text":"Whom resist stedfast in the faith, knowing that the same afflictions are accomplished in your brethren that are in the world.","ref":"1 Peter 5:9","synthesized":"Resist him, standing firm in your faith and in the knowledge that your brothers throughout the world are undergoing the same kinds of suffering.","sources":{"KJV":{"text":"Whom resist stedfast in the faith, knowing that the same afflictions are accomplished in your brethren that are in the world."},"BSB":{"text":"Resist him, standing firm in your faith and in the knowledge that your brothers throughout the world are undergoing the same kinds of suffering."}},"definableWords":["faith","knowledge"],"peopleInVerse":[]},"10":{"text":"But the God of all grace, who hath called us unto his eternal glory by Christ Jesus, after that ye have suffered a while, make you perfect, stablish, strengthen, settle you.","ref":"1 Peter 5:10","synthesized":"And after you have suffered for a little while, the God of all grace, who has called you to His eternal glory in Christ, will Himself restore you, secure you, strengthen you, and establish you.","sources":{"KJV":{"text":"But the God of all grace, who hath called us unto his eternal glory by Christ Jesus, after that ye have suffered a while, make you perfect, stablish, strengthen, settle you."},"BSB":{"text":"And after you have suffered for a little while, the God of all grace, who has called you to His eternal glory in Christ, will Himself restore you, secure you, strengthen you, and establish you."}},"definableWords":["God","grace","eternal","glory","Christ"],"peopleInVerse":[]},"11":{"text":"To him be glory and dominion for ever and ever. Amen.","ref":"1 Peter 5:11","synthesized":"To Him be the power forever and ever. Amen.","sources":{"KJV":{"text":"To him be glory and dominion for ever and ever. Amen."},"BSB":{"text":"To Him be the power forever and ever. Amen."}},"definableWords":[],"peopleInVerse":[]},"12":{"text":"By Silvanus, a faithful brother unto you, as I suppose, I have written briefly, exhorting, and testifying that this is the true grace of God wherein ye stand.","ref":"1 Peter 5:12","synthesized":"Through Silvanus, whom I regard as a faithful brother, I have written to you briefly, encouraging you and testifying that this is the true grace of God. Stand firm in it.","sources":{"KJV":{"text":"By Silvanus, a faithful brother unto you, as I suppose, I have written briefly, exhorting, and testifying that this is the true grace of God wherein ye stand."},"BSB":{"text":"Through Silvanus, whom I regard as a faithful brother, I have written to you briefly, encouraging you and testifying that this is the true grace of God. Stand firm in it."}},"definableWords":["brother","grace","God","stand"],"peopleInVerse":[]},"13":{"text":"The church that is at Babylon, elected together with you, saluteth you; and so doth Marcus my son.","ref":"1 Peter 5:13","synthesized":"The church in Babylon, chosen together with you, sends you greetings, as does my son Mark.","sources":{"KJV":{"text":"The church that is at Babylon, elected together with you, saluteth you; and so doth Marcus my son."},"BSB":{"text":"The church in Babylon, chosen together with you, sends you greetings, as does my son Mark."}},"definableWords":["church","Babylon","son"],"peopleInVerse":[]},"14":{"text":"Greet ye one another with a kiss of charity. Peace be with you all that are in Christ Jesus. Amen.","ref":"1 Peter 5:14","synthesized":"Greet one another with a kiss of love.  Peace to all of you who are in Christ.","sources":{"KJV":{"text":"Greet ye one another with a kiss of charity. Peace be with you all that are in Christ Jesus. Amen."},"BSB":{"text":"Greet one another with a kiss of love.  Peace to all of you who are in Christ."}},"definableWords":["one","love","peace","Christ"],"peopleInVerse":[]}}}};